{"command": "python3 -c "
import subprocess
# Try using ffmpeg from common paths
paths = ['/usr/bin/ffmpeg', '/usr/local/bin/ffmpeg', '/snap/bin/ffmpeg']
for p in paths:
    try:
        r = subprocess.run([p, '-version'], capture_output=True, timeout=5)
        if b'ffmpeg' in r.stderr:
            print(f'Found: {p}')
            print(r.stderr.decode().split(chr(10))[0])
            break
    except:
        pass
else:
    print('No ffmpeg binary found')
""}

